const demandAutomations = flow.get('stored_demand') || {};

const devices = Object.keys(msg.payload);

for (const device of devices) {
    if (device in demandAutomations) {
        const demandAutomation = demandAutomations[device];
        const activePower = msg.payload[device][0]['Potencia Ativa Trifásica'];
        if (!activePower) {
            continue;
        }
        
        const minPower = demandAutomation.minPower * 1000; // kW -> W
        const maxPower = demandAutomation.maxPower * 1000; // kW -> W

        if (activePower > maxPower) {
            // Need to turn off and ignore.
            node.send([{
                device,
                payload: demandAutomation
            }, null]);
        }
        
        if (activePower < minPower) {
            // No need to turn on, but remove from ignored.
            node.send([null, {
                device,
                payload: demandAutomation,
            }]);
        }
    }
}
